import { IsInt, IsOptional, IsEnum, Min, Max } from 'class-validator';
import { ScopeEnum } from '../../common/pagination.dto';

export class GeographyQueryDto {
  @IsInt()
  @Min(2020)
  @Max(2024)
  @IsOptional()
  fiscalYear?: number;

  @IsEnum(ScopeEnum)
  scope: ScopeEnum;
}

import { Controller, Get, Param, Query } from '@nestjs/common';
import { GeographyService, QueryStatesInput } from './geography.service';
import { GeoSpendingSnapshot } from './geo-spending-snapshot.entity';

@Controller('geography')
export class GeographyController {
  constructor(private readonly geographyService: GeographyService) {}

  @Get('states')
  getStates(
    @Query('fiscalYear') fiscalYear?: number,
    @Query('agencyId') agencyId?: number,
    @Query('scope') scope?: string,
  ): Promise<GeoSpendingSnapshot[]> {
    return this.geographyService.queryStates({ fiscalYear, agencyId, scope });
  }

  @Get('state/:code')
  getStateDetail(@Param('code') code: string): Promise<GeoSpendingSnapshot[]> {
    return this.geographyService.getStateDetail(code);
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { GeographyController } from './geography.controller';
import { GeographyService } from './geography.service';
import { GeoSpendingSnapshot } from './geo-spending-snapshot.entity';

describe('GeographyController', () => {
  let controller: GeographyController;
  let service: GeographyService;

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      controllers: [GeographyController],
      providers: [
        {
          provide: GeographyService,
          useValue: {
            queryStates: jest.fn(),
            getStateDetail: jest.fn(),
          },
        },
      ],
    }).compile();

    controller = module.get<GeographyController>(GeographyController);
    service = module.get<GeographyService>(GeographyService);
  });

  it('should query states with fiscalYear', async () => {
    const mockResult: GeoSpendingSnapshot[] = [
      {
        id: 1,
        stateCode: 'AL',
        stateName: 'Alabama',
        fiscalYear: 2024,
        agencyId: 1,
        scope: 'state',
        obligatedAmount: 500000,
        awardCount: 10,
        population: 5000000,
        perCapita: 100,
      } as GeoSpendingSnapshot,
    ];
    jest.spyOn(service, 'queryStates').mockResolvedValue(mockResult);

    const result = await controller.getStates(2024);

    expect(result).toEqual(mockResult);
    expect(service.queryStates).toHaveBeenCalledWith({ fiscalYear: 2024 });
  });

  it('should query states with fiscalYear and agencyId', async () => {
    const mockResult: GeoSpendingSnapshot[] = [];
    jest.spyOn(service, 'queryStates').mockResolvedValue(mockResult);

    const result = await controller.getStates(2024, 2);

    expect(result).toEqual(mockResult);
    expect(service.queryStates).toHaveBeenCalledWith({
      fiscalYear: 2024,
      agencyId: 2,
    });
  });

  it('should query states with scope', async () => {
    const mockResult: GeoSpendingSnapshot[] = [];
    jest.spyOn(service, 'queryStates').mockResolvedValue(mockResult);

    const result = await controller.getStates(2024, undefined, 'county');

    expect(result).toEqual(mockResult);
    expect(service.queryStates).toHaveBeenCalledWith({
      fiscalYear: 2024,
      scope: 'county',
    });
  });

  it('should query states without agencyId for combined-agency data', async () => {
    const mockResult: GeoSpendingSnapshot[] = [];
    jest.spyOn(service, 'queryStates').mockResolvedValue(mockResult);

    const result = await controller.getStates(2024);

    expect(result).toEqual(mockResult);
    expect(service.queryStates).toHaveBeenCalledWith({ fiscalYear: 2024 });
  });

  it('should return state detail for a given state code', async () => {
    const mockResult: GeoSpendingSnapshot[] = [
      {
        id: 1,
        stateCode: 'CA',
        stateName: 'California',
        fiscalYear: 2024,
        agencyId: 1,
        scope: 'state',
        obligatedAmount: 1500000,
        awardCount: 30,
        population: 40000000,
        perCapita: 3750,
      } as GeoSpendingSnapshot,
    ];
    jest.spyOn(service, 'getStateDetail').mockResolvedValue(mockResult);

    const result = await controller.getStateDetail('CA');

    expect(result).toEqual(mockResult);
    expect(service.getStateDetail).toHaveBeenCalledWith('CA');
  });
});

import { Controller, Get, Param, Query } from '@nestjs/common';
import { DisasterService, QueryRatiosParams, QueryStatesParams } from './disaster.service';

@Controller('disaster')
export class DisasterController {
  constructor(private readonly service: DisasterService) {}

  @Get('overview')
  async getOverview(
    @Query('defGroup') defGroup?: string,
  ) {
    const params: { defGroup?: string } = {};
    if (defGroup) params.defGroup = defGroup;
    return this.service.getOverview(params);
  }

  @Get('states')
  async queryStates(
    @Query('defGroup') defGroup?: string,
    @Query('fiscalYear') fiscalYear?: string,
  ) {
    const params: QueryStatesParams = {};
    if (defGroup) params.defGroup = defGroup;
    if (fiscalYear) params.fiscalYear = parseInt(fiscalYear, 10);
    return this.service.queryStates(params);
  }

  @Get('recovery-ratios')
  async queryRatios(
    @Query('fiscalYear') fiscalYear?: string,
  ) {
    const params: QueryRatiosParams = {};
    if (fiscalYear) params.fiscalYear = parseInt(fiscalYear, 10);
    return this.service.queryRatios(params);
  }

  @Get('state/:code')
  async getStateProfile(@Param('code') code: string) {
    return this.service.getStateProfile(code);
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { DisasterController } from './disaster.controller';
import { DisasterService } from './disaster.service';

describe('DisasterController', () => {
  let controller: DisasterController;
  let service: DisasterService;

  const mockService = {
    getOverview: jest.fn(),
    queryStates: jest.fn(),
    queryRatios: jest.fn(),
    getStateProfile: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      controllers: [DisasterController],
      providers: [
        { provide: DisasterService, useValue: mockService },
      ],
    }).compile();

    controller = module.get<DisasterController>(DisasterController);
    service = module.get<DisasterService>(DisasterService);
  });

  it('should be defined', () => {
    expect(controller).toBeDefined();
  });

  it('calls service.getOverview and returns the result', async () => {
    const overviewData = [
      { defGroup: 'CA', totalObligated: 300000, totalAwardCount: 15, stateCount: 2, highestPerCapitaState: 'California', highestPerCapita: 1000, coverageGapCount: 1 },
      { defGroup: '01', totalObligated: 50000, totalAwardCount: 3, stateCount: 1, highestPerCapitaState: 'Florida', highestPerCapita: 200, coverageGapCount: 0 },
    ];
    mockService.getOverview.mockResolvedValue(overviewData);

    const result = await controller.getOverview();

    expect(result).toEqual(overviewData);
    expect(service.getOverview).toHaveBeenCalled();
  });

  it('calls service.queryStates with defGroup and fiscalYear query params', async () => {
    const statesData = [
      { id: 1, defGroup: 'CA', stateCode: 'CA', stateName: 'California', obligatedAmount: 200000, awardCount: 10, perCapita: 1000, population: 200 },
      { id: 2, defGroup: 'CA', stateCode: 'NY', stateName: 'New York', obligatedAmount: 100000, awardCount: 5, perCapita: 500, population: 200 },
    ];
    mockService.queryStates.mockResolvedValue(statesData);

    const result = await controller.queryStates('CA', '2024');

    expect(result).toEqual(statesData);
    expect(service.queryStates).toHaveBeenCalledWith({ defGroup: 'CA', fiscalYear: 2024 });
  });

  it('calls service.queryStates with only defGroup', async () => {
    const statesData: any[] = [];
    mockService.queryStates.mockResolvedValue(statesData);

    const result = await controller.queryStates('CA', undefined);

    expect(result).toEqual(statesData);
    expect(service.queryStates).toHaveBeenCalledWith({ defGroup: 'CA' });
  });

  it('calls service.queryRatios with fiscalYear query param and sorts ascending', async () => {
    const ratiosData = [
      { id: 1, stateCode: 'CA', stateName: 'California', fiscalYear: 2024, femaObligated: 300000, fedSpendingObligated: 100000, recoveryRatio: 0.3, declarationCount: 2, dominantIncidentType: 'Earthquake' },
      { id: 2, stateCode: 'FL', stateName: 'Florida', fiscalYear: 2024, femaObligated: 50000, fedSpendingObligated: 50000, recoveryRatio: 1.0, declarationCount: 1, dominantIncidentType: 'Hurricane' },
    ];
    mockService.queryRatios.mockResolvedValue(ratiosData);

    const result = await controller.queryRatios('2024');

    expect(result).toEqual(ratiosData);
    expect(service.queryRatios).toHaveBeenCalledWith({ fiscalYear: 2024 });
  });

  it('calls service.queryRatios with no fiscalYear', async () => {
    const ratiosData: any[] = [];
    mockService.queryRatios.mockResolvedValue(ratiosData);

    const result = await controller.queryRatios(undefined);

    expect(result).toEqual(ratiosData);
    expect(service.queryRatios).toHaveBeenCalledWith({});
  });

  it('calls service.getStateProfile with state code parameter', async () => {
    const profileData = {
      stateCode: 'NY',
      stateName: 'New York',
      totalObligated: 150000,
      totalAwardCount: 8,
      ratios: [{ recoveryRatio: 2.0, femaObligated: 100000, fedSpendingObligated: 200000, declarationCount: 1 }],
      declarationCount: 1,
    };
    mockService.getStateProfile.mockResolvedValue(profileData);

    const result = await controller.getStateProfile('NY');

    expect(result).toEqual(profileData);
    expect(service.getStateProfile).toHaveBeenCalledWith('NY');
  });

  it('returns null for getStateProfile when no data exists', async () => {
    mockService.getStateProfile.mockResolvedValue(null);

    const result = await controller.getStateProfile('ZZ');

    expect(result).toBeNull();
    expect(service.getStateProfile).toHaveBeenCalledWith('ZZ');
  });
});

import { Controller, Get, Param, Query } from '@nestjs/common';
import { AgenciesService } from './agencies.service';
import { ApiResponse, AgencySummary } from '@shared/interfaces';
import { SpendingRecord } from '../spending/spending-record.entity';

@Controller('agencies')
export class AgenciesController {
  constructor(private readonly agenciesService: AgenciesService) {}

  @Get()
  list(@Query('fiscalYear') fiscalYear?: string): Promise<ApiResponse<{ id: number; name: string; totalCents: number }[]>> {
    return this.agenciesService.findAllWithTotals(fiscalYear ? Number(fiscalYear) : undefined);
  }

  @Get(':id/summary')
  summary(@Param('id') id: string): Promise<AgencySummary | null> {
    return this.agenciesService.findSummary(Number(id));
  }

  @Get(':id/spotlight')
  spotlight(@Param('id') id: string): Promise<SpendingRecord[] | null> {
    return this.agenciesService.findSpotlight(Number(id));
  }
}

import { AgenciesController } from './agencies.controller';
import { AgenciesService } from './agencies.service';
import { ApiResponse, Agency, AgencySummary } from '@shared/interfaces';
import { SpendingRecord } from '../spending/spending-record.entity';

describe('AgenciesController', () => {
  let controller: AgenciesController;
  let service: AgenciesService;

  beforeEach(() => {
    const mockService = {
      findAllWithTotals: jest.fn(),
      findSummary: jest.fn(),
      findSpotlight: jest.fn(),
    };
    service = mockService as any;
    controller = new AgenciesController(service);
  });

  describe('list', () => {
    interface TestCase {
      name: string;
      fiscalYear?: string;
      expectedFy?: number;
      serviceReturn: ApiResponse<{ id: number; name: string; totalCents: number }[]>;
      expected: ApiResponse<{ id: number; name: string; totalCents: number }[]>;
    }

    const testTable: TestCase[] = [
      {
        name: 'returns paginated ApiResponse with agency list when no fiscalYear param is supplied',
        expectedFy: undefined,
        serviceReturn: {
          data: [
            { id: 1, name: 'Agency A', totalCents: 300000 },
          ],
          meta: { total: 6, page: 1, pageSize: 6 },
        },
        expected: {
          data: [
            { id: 1, name: 'Agency A', totalCents: 300000 },
          ],
          meta: { total: 6, page: 1, pageSize: 6 },
        },
      },
      {
        name: 'passes a numeric fiscalYear query param through to the service',
        fiscalYear: '2023',
        expectedFy: 2023,
        serviceReturn: {
          data: [
            { id: 1, name: 'Agency A', totalCents: 300000 },
          ],
          meta: { total: 6, page: 1, pageSize: 6 },
        },
        expected: {
          data: [
            { id: 1, name: 'Agency A', totalCents: 300000 },
          ],
          meta: { total: 6, page: 1, pageSize: 6 },
        },
      },
      {
        name: 'omits fiscalYear when the query param is an empty string',
        fiscalYear: '',
        expectedFy: undefined,
        serviceReturn: {
          data: [],
          meta: { total: 0, page: 1, pageSize: 0 },
        },
        expected: {
          data: [],
          meta: { total: 0, page: 1, pageSize: 0 },
        },
      },
    ];

    it.each(testTable)('$name', async ({ fiscalYear, expectedFy, serviceReturn, expected }) => {
      service.findAllWithTotals.mockResolvedValue(serviceReturn);
      const result = await controller.list(fiscalYear);
      expect(service.findAllWithTotals).toHaveBeenCalledWith(expectedFy);
      expect(result).toEqual(expected);
    });
  });

  describe('summary', () => {
    interface TestCase {
      name: string;
      serviceReturn: AgencySummary;
      expected: AgencySummary;
    }

    const testTable: TestCase[] = [
      {
        name: 'returns summary for given agency id',
        serviceReturn: {
          agency: { id: 1, name: 'Agency A', abbreviation: 'A', toptierCode: '001' },
          currentFyTotal: 300000,
          priorFyTotal: 200000,
          yoyChange: 50,
        },
        expected: {
          agency: { id: 1, name: 'Agency A', abbreviation: 'A', toptierCode: '001' },
          currentFyTotal: 300000,
          priorFyTotal: 200000,
          yoyChange: 50,
        },
      },
    ];

    it.each(testTable)('$name', async ({ serviceReturn, expected }) => {
      service.findSummary.mockResolvedValue(serviceReturn);
      const result = await controller.summary(1);
      expect(service.findSummary).toHaveBeenCalledWith(1);
      expect(result).toEqual(expected);
    });
  });

  describe('spotlight', () => {
    interface TestCase {
      name: string;
      serviceReturn: SpendingRecord[];
      expected: SpendingRecord[];
    }

    const testTable: TestCase[] = [
      {
        name: 'returns spotlight data for given agency id',
        serviceReturn: [
          { id: 1, agencyId: 1, fiscalYear: 2026, quarter: 1, awardTypeLabel: 'Grant', awardTypeCodes: 'G', obligatedAmount: 300000, outlayAmount: 230000, awardCount: 15 } as SpendingRecord,
        ],
        expected: [
          { id: 1, agencyId: 1, fiscalYear: 2026, quarter: 1, awardTypeLabel: 'Grant', awardTypeCodes: 'G', obligatedAmount: 300000, outlayAmount: 230000, awardCount: 15 } as SpendingRecord,
        ],
      },
    ];

    it.each(testTable)('$name', async ({ serviceReturn, expected }) => {
      service.findSpotlight.mockResolvedValue(serviceReturn);
      const result = await controller.spotlight(1);
      expect(service.findSpotlight).toHaveBeenCalledWith(1);
      expect(result).toEqual(expected);
    });
  });
});
